import { Flag } from '~/modules/elements/flag';
import { colorSets } from '~/modules/game-engine/drawing/styles';
import { getEurovisionYear } from '~/modules/songs/utils/special-songs-theme-checks';
import isoCodeToCountry from '~/modules/utils/iso-code-to-country';
import eurovisionIcon from '~/routes/sing-a-song/song-selection/components/song-card/eurovision-icon.svg';
import { PlaylistEntry } from '~/routes/sing-a-song/song-selection/hooks/use-playlists';

const eurovisionGradient = [
  colorSets.eurovisionRed.text,
  colorSets.eurovisionPink.text,
  colorSets.eurovisionBlue.text,
  colorSets.eurovisionGreen.text,
  colorSets.eurovisionPink.text,
  colorSets.eurovisionRed.text,
].join(', ');

const EurovisionDisplay = ({ children }: { children: React.ReactNode }) => (
  <>
    <style>{`
      @keyframes playlist-gradient {
        0% { background-position: 0% 0%; }
        100% { background-position: 400% 400%; }
      }
    `}</style>
    <span
      style={{
        backgroundImage: `linear-gradient(90deg, ${eurovisionGradient})`,
        backgroundSize: '200% 200%',
        backgroundClip: 'text',
        WebkitBackgroundClip: 'text',
        color: 'transparent',
        display: 'flex',
        alignItems: 'center',
        animation: 'playlist-gradient 15s linear infinite',
      }}>
      {children}
    </span>
  </>
);

export const EurovisionLogo = ({ src, alt }: { src: string; alt: string }) => (
  <>
    <style>{`
      @keyframes heartbeat {
        0%  { transform: scale(0.85); }
        10% { transform: scale(1); }
        20% { transform: scale(0.85); }
        30% { transform: scale(1); }
        40% { transform: scale(0.85); }
        100% { transform: scale(0.85); }
      }
    `}</style>
    <img src={src} alt={alt} style={{ width: '1em', height: '1em', animation: 'heartbeat 1.5s infinite' }} />
  </>
);

const SFlag = ({ isocode }: { isocode: string }) => (
  <Flag isocode={isocode} style={{ width: '1em', height: '1em', objectFit: 'contain' }} />
);

// eslint-disable-next-line react-refresh/only-export-components
export const eurovisionPlaylist: PlaylistEntry = {
  name: 'Eurovision',
  display: (
    <EurovisionDisplay>
      Euro
      <EurovisionLogo src={eurovisionIcon} alt="Eurovision logo" />
      ision
    </EurovisionDisplay>
  ),
  filters: { edition: 'esc', skipExcludedLanguages: true },
  hideNew: true,
  groupData: (song) => {
    const flag = song.artistOrigin ? <SFlag isocode={song.artistOrigin} /> : 'Other';
    return {
      name: song.artistOrigin ?? 'Other',
      displayLong: song.artistOrigin ? (
        <>
          {flag} {isoCodeToCountry(song.artistOrigin)}
        </>
      ) : (
        'Other'
      ),
      displayShort: flag,
    };
  },
  sortingFn: (a, b) => {
    const yearA = getEurovisionYear(a);
    const yearB = getEurovisionYear(b);
    if (yearA && yearB) {
      return +yearB - +yearA;
    }
    return 0;
  },
  postGrouping: (groups) => {
    let finalGroups = groups;
    // group single item groups into "Other"
    const singleItemGroups = groups.filter((group) => group.songs.length <= 1);
    if (singleItemGroups.length) {
      let other = groups.find((group) => group.name === 'Other');
      if (!other) {
        other = { name: 'Other', songs: [] };
        groups.push(other);
      }
      other.displayLong = (
        <>
          <SFlag isocode="eu" /> Other
        </>
      );
      other.songs = singleItemGroups.map((group) => group.songs[0]);
      finalGroups = groups.filter((group) => group.name === 'Other' || group.songs.length > 1);
    }
    // sort by country name
    finalGroups.sort((a, b) => {
      if (a.name === 'Other') return 1;
      if (b.name === 'Other') return -1;
      return (
        isoCodeToCountry(a.songs[0].song.artistOrigin!)?.localeCompare(
          isoCodeToCountry(b.songs[0].song.artistOrigin!) ?? '',
        ) ?? 0
      );
    });

    return finalGroups;
  },
};
